from flask import Flask, jsonify
from pymemcache.client.base import Client
import sqlite3
import time
import json

app = Flask(__name__)

# Initialize Memcached client
memcached_client = Client(('localhost', 11211))

# Database setup
def init_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT)''')
    c.execute("INSERT OR IGNORE INTO users (id, name, email) VALUES (1, 'John Doe', 'john@example.com')")
    conn.commit()
    conn.close()

# Cache decorator for database queries
def cache_db_query(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"db_query:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = memcached_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            memcached_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Cache decorator for API responses
def cache_api_response(ttl=60):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"api_response:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = memcached_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            memcached_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Database query with caching
@cache_db_query(ttl=300)
def get_users_from_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users")
    users = c.fetchall()
    conn.close()
    return users

# API endpoint with caching
@app.route('/users', methods=['GET'])
@cache_api_response(ttl=60)
def get_users():
    users = get_users_from_db()
    return jsonify([{'id': user[0], 'name': user[1], 'email': user[2]} for user in users])

# Health check endpoint
